 1	import type { FC } from 'react';
 2	
 3	import type { ResourceField } from '@components/common/utils/types';
 4	import VirtualMachineConcernsCell from '@components/Concerns/VirtualMachineConcernsCell';
 5	import VirtualMachinePowerStateCell from '@components/PowerState/VirtualMachinePowerStateCell';
 6	import { nameColumn } from '@components/VsphereFoldersTable/utils/constants';
 7	import type { VmRow } from '@components/VsphereFoldersTable/utils/types';
 8	import type { VSphereVM } from '@kubev2v/types';
 9	import { Td, TreeRowWrapper } from '@patternfly/react-table';
10	import { EMPTY_MSG } from '@utils/constants';
11	
12	type VmTreeRowProps = {
13	  row: VmRow;
14	  columns: ResourceField[];
15	};
16	
17	const VmCells: Record<string, FC<{ row: VmRow }>> = {
18	  concerns: ({ row }) => <VirtualMachineConcernsCell vmData={row.vmData} />,
19	  host: ({ row }) => <>{row.vmData.hostName ?? EMPTY_MSG}</>,
20	  path: ({ row }) => <>{(row.vmData.vm as VSphereVM).path ?? EMPTY_MSG}</>,
21	  power: ({ row }) => <VirtualMachinePowerStateCell vmData={row.vmData} />,
22	};
23	
24	const VmTreeRow: FC<VmTreeRowProps> = ({ columns, row }) => {
25	  return (
26	    <TreeRowWrapper data-testid={row.key} key={row.key} row={{ props: row?.treeRow?.props }}>
27	      <Td treeRow={row.treeRow} dataLabel={nameColumn.label}>
28	        {row.vmData.name}
29	      </Td>
30	      {columns.map((col) => {
31	        if (!col.isVisible) return null;
32	        const Component = VmCells[col.resourceFieldId!];
33	        return (
34	          <Td key={col.resourceFieldId} dataLabel={col.label ?? ''}>
35	            <Component row={row} />
36	          </Td>
37	        );
38	      })}
39	    </TreeRowWrapper>
40	  );
41	};
42	
43	export default VmTreeRow;

